var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어라? 내가 교실을 잘못 들어왔나?","JPN":"あれ？　あたし、教室を間違えたのかな？","ENG":"Oh? Did I walk into the wrong classroom?","TWN":"嗯？我是不是走錯教室了？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"잘못 들어오지 않았소. 눈앞에 보이는 건 분명 나이엘이오.","JPN":"間違えていません。目の前にいるのは確かにナイエルです。","ENG":"You did not. The person in front of you is, without a doubt, Naielle.","TWN":"在下沒走錯，眼前的確是奈爾。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"지금까지 봉사활동을 해오면서 마음을 다잡은 것일지도 모르겠구려.","JPN":"これまでのボランティア活動で、心を入れ替えたのかもしれませんね。","ENG":"Perhaps all the volunteering has calmed her mind.","TWN":"難道是志工活動改變她的嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"웬일이야? 네가 오리엔테이션부터 수업을 들으러 오다니.","JPN":"あなたがオリエンテーションから授業に参加するなんて、どうしたの？","ENG":"What are you doing here? I can't believe you came to class orientation.","TWN":"什麼風把你吹來了？你居然從新學期說明會就開始就來上課了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥, 그 낙하산이 얼마나 대단한 사람인지 시험하러 온 것뿐이야.","JPN":"ふん。あのコネ教師がどれほどすごい人なのか、試しに来ただけよ。","ENG":"Hmph. I'm just here to test the teacher who got in through favoritism.","TWN":"哼，我只是來試試那個空降部隊到底有多厲害。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"기준 미달인 사람이 감히 선생이랍시고……\xA0\xA0","JPN":"基準以下のくせに先生を名乗るなんて……\xA0\xA0","ENG":"How dare this unqualified person try to–\xA0\xA0","TWN":"不合格的人竟敢自稱老師……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"우왓, 깜짝이야! 언제부터 옆에 있던 거야?!","JPN":"わっ、びっくりした！　いつからそこにいたのよ！","ENG":"WHOA!! How long have you been there?!","TWN":"哇，嚇我一跳！你什麼時候來的？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"시험하러 온 것뿐이야…… 부터?","JPN":"試しに来ただけよ……から？","ENG":"Since when you were talking about testing... me?","TWN":"測試你一下……什麼叫從哪來？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그, 그럼 처음부터 있었던 거잖아……!","JPN":"じゃ、じゃあ最初からいたんじゃない……！","ENG":"Th-then you were there from the start...!","TWN":"剛，剛才不是在那嗎……！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"전혀 눈치채지 못했어! 어떻게 한 거지?","JPN":"全然気づけなかった……！　どうして？","ENG":"I didn't even notice her! How did she do that?","TWN":"完全沒有察覺到！你是怎麼做到的？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"자리에 앉아 줄래……?","JPN":"席に座ってくれる……？","ENG":"Could you all take your seats...?","TWN":"能坐下嗎……？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"시작했으니까……. 수업.","JPN":"始まったから……授業。","ENG":"The class has... already started.","TWN":"開始……上課。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"모두 안녕……. 진보라라고 해…….","JPN":"こんにちは……先生の名前はタカダ・シホ……","ENG":"Hello, everyone... I am Jin Bora...","TWN":"你們好……我叫陳寶拉……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"시뮬레이션…… 모의전투 강사를 담당했어.","JPN":"シミュレーション……模擬戦闘の講師を担当することになった。","ENG":"I am going to be your instructor... for the simulation.","TWN":"我是負責模擬戰鬥的講師。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"정식 수업은 내일부터니까…… 오늘은 간단하게.","JPN":"正式な授業は明日からなので……今日は簡単に。","ENG":"The class will start tomorrow, so... I'll make this one quick.","TWN":"正式課程從明天開始……今天就簡單一點。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"그럼 설명해 줄게…… 내일 수업에 대해.","JPN":"じゃあ、説明するよ……明日の授業のこと。","ENG":"Here's what you need to know... about tomorrow's class.","TWN":"那我來解釋一下……關於明天的課程。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"시뮬레이션엔 새로운 모드가 도입될 거야…… 카운터즈 레거시.","JPN":"シミュレーションには、新しいモードが導入される……カウンターズ・レガシー。","ENG":"The simulation will have a new mode implemented... Counters Legacy.","TWN":"即將引入一個新的模擬模式……制裁者的遺產。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"지금까진 아카데미에서만 접속했었지……?","JPN":"今までは、アカデミーでしかアクセスしてなかったよね……？","ENG":"Only the Academy had access so far, right?","TWN":"到目前為止，你們一直是從學院登入的吧……？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"확장할 거야…… 서버……. 그라운드 원의 카운터들도 접속할 수 있게.","JPN":"拡張するんだよ……サーバー……グラウンド・ワンのカウンターもアクセスできるように。","ENG":"We are expanding... the server... so Counters from Ground One can also access it.","TWN":"會擴展……伺服器……讓G1制裁者們也能連接得上。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"잠깐, 일반인들도 접속할 수 있다고?","JPN":"それって、一般人もアクセスできるってこと？","ENG":"Wait, normal people can also access it?","TWN":"等等，普通人也能登入嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L35_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"시뮬레이션 서버는 관리국과 아카데미에서만 접속 가능한 거로 알고 있는데?","JPN":"シミュレーションサーバーは管理局とアカデミーでしかアクセスできないはずよ。","ENG":"As I know, the simulation server was only accessible at the Administration and the Academy.","TWN":"我知道模擬伺服器只能從管理局和學院連線？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"서버는 분리할 거야…… 3개로.","JPN":"サーバーは分離する……3つに。","ENG":"The server will be split... into three.","TWN":"伺服器將會分成……3個。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"아카데미, 그라운드 원, 그리고…… 모두가 만날 수 있는 서버.","JPN":"アカデミー、グラウンド・ワン、そして……誰でも入場できるサーバー。","ENG":"Academy, Ground One, and... a server where everyone can meet.","TWN":"學院、G1，以及……所有人都能登入的伺服器。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"하지만…… 당분간 아카데미 서버만 이용 가능해.","JPN":"でも……しばらく、利用できるのはアカデミーサーバーだけ。","ENG":"But... only the Academy server will be available for the time being.","TWN":"但是……目前只能使用學院伺服器。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"시뮬레이션이니까 다칠 위험도 없고…… 좋은 훈련이 될 거야.","JPN":"シミュレーションだから怪我する恐れもない……きっといい訓練になる。","ENG":"Because it's a simulation, there is no risk of getting injured... and it will be good training.","TWN":"因為是模擬訓練，所以沒有受傷的風險……是個不錯的訓練模式。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"학생들의 실력이 못 미더운 건 아니겠지?","JPN":"生徒たちの実力が信じられないわけじゃないわよね。","ENG":"Or, do you lack faith in the students' skills?","TWN":"你是不相信學生們的實力吧？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"아냐…… 세상이 넓다는 걸 알아줬으면 해.","JPN":"違う……世界が広いということを、知ってほしい。","ENG":"No... I just want all of you to know how big the world is.","TWN":"不……我只是希望你能明白，世界是很大的。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"많으니까…… 그라운드 원의 강자들은.","JPN":"無数にいるの……グラウンド・ワンの強者は。","ENG":"There are lots... of strong people in Ground One.","TWN":"因為有很多……G1的強者們。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"틀린 말은 아니지. 그 편입생들도 엄청 강했으니까…….","JPN":"確かにそうね。あの編入生たちもすごく強かったし。","ENG":"You're not wrong. Even those transfer students were pretty strong, too...","TWN":"沒錯，那些轉學生也非常強……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L1_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"CRF 출력으로 카운터 등급을 매겼었지……? 지금까진.","JPN":"CRFの出力でカウンターランクをつけてたよね……今までは。","ENG":"Your Counter Grades were determined by your CRF output, right...? Until now.","TWN":"以前是根據CRF輸出來評定制裁者等級的……？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"카운터즈 레거시를 도입하면서…… 바꿔볼 거야…… 평가 기준.","JPN":"カウンターズ・レガシーの導入とともに……変えてみる……評価基準。","ENG":"With the implementation of Counters Legacy... it will change… the criteria…","TWN":"隨著制裁者的遺產的引入……我要改變……評估標準。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"아니라고 생각해…… 카운터 등급이 절대적인 강함의 기준이 되는 건.","JPN":"違うと思うの……カウンターランクが、絶対的な強さの基準になるのは。","ENG":"I don't think... that the Counter Grade should be the absolute indicator of one's strength.","TWN":"我認為……制裁者的等級並不是衡量絕對實力的標準。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"아카데미 학생들은…… 무궁한 가능성이 있으니까.","JPN":"アカデミーの生徒たちは……無限の可能性を秘めているから。","ENG":"Because Academy students have... endless possibilities.","TWN":"學院的學生們……有著無限的可能性。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"잠깐, 어떻게 평가할 건지 구체적으로 얘기해 줘.","JPN":"じゃあ、どう評価するつもりなのか具体的に教えてちょうだい。","ENG":"Hold on. Could you elaborate on how we will be graded then?","TWN":"等一下，具體說說怎麼評價。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L8_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"구현했어…… 이면 세계 환경…… 이걸로 다이브 실습을 대체할 거야.","JPN":"具現化した……裏世界の環境……これでダイブの実習を代替する。","ENG":"The Counterside's environment... has been emulated... This will substitute your Dive training.","TWN":"實現了……異界環境……用這個來代替躍入訓練吧。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"매우 위험하니까…… 실제 다이브 실습은.","JPN":"非常に危険だから……ダイブの実習は。","ENG":"It's dangerous... Dive training.","TWN":"因為實際的躍入訓練……非常危險。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"필드 조사, 몬스터 섬멸 퀘스트, 이면 세계 환경 적응, 다양하게 수업을…….","JPN":"フィールドの調査、モンスター殲滅クエスト、裏世界環境への適応、様々な授業を……","ENG":"Field investigations, monster elimination quests, training to adapt to the Counterside, and various other classes–","TWN":"野外調查、怪物殲滅任務、異界環境適應，各種課程……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥! 말도 안 되는 소리!","JPN":"ふん！　バカバカしい！","ENG":"Hmph! Nonsense!","TWN":"哼！這怎麼可能！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이 몸은 이미 수많은 실전을 거쳐왔거든?","JPN":"このナイエル様はすでに数多くの実戦を経験してるのよ！","ENG":"I've already experienced countless real battles!","TWN":"我可是經歷了無數實戰的！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"어떻게 됐어……? 실전 때.","JPN":"どうなったの……？　実戦の時。","ENG":"How did it go...? During the real battle?","TWN":"實戰時……情況怎麼樣？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그, 그러니까…….","JPN":"そ、それは……","ENG":"W-well...","TWN":"那，那個……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"계속 해도 될까……. 수업.\xA0","JPN":"続けていい……？　授業。\xA0","ENG":"May I continue with it…? My class.","TWN":"可以繼續了嗎。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"나이엘이 저렇게나 진지하게 수업을 듣는 모습은 처음 보는구려.","JPN":"ナイエルがあれほど真面目に授業を受ける姿は初めて見る気がします。","ENG":"It is a first to see Naielle taking a class this seriously.","TWN":"還是第一次見到奈爾如此認真地聽課呢。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"내심 보라 선생님이 마음에 들었던 것일지도 모르겠소.","JPN":"内心、タカダ先生が気に入ったのかもしれませんね。","ENG":"It almost seems that she likes Ms. Jin.","TWN":"或許她內心是喜歡寶拉老師的。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"내가 보기엔 어떻게든 트집 잡으려는 것처럼 보이는데…….","JPN":"どうにかして揚げ足を取りたいようにしか見えないけど……","ENG":"It just looks like she's trying to nitpick her...","TWN":"我怎麼覺得她只是在找碴……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"흠…… <color=#ffd34c>가람</color> 선생님이 많이 늦네.","JPN":"うーん……<color=#ffd34c>ヒカリ</color>先生が遅いね。","ENG":"Hmm... <color=#ffd34c>Garam</color> seems to be running late.","TWN":"嗯…… <color=#ffd34c>嘉蘭</color>老師怎麼還不來。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"혹시 질문 있니……? 지금까지 말한 내용 중에서.","JPN":"聞きたいこと、ある……？　今までの話で。","ENG":"Are there any other questions...? About what we talked about?","TWN":"有問題嗎……？關於剛才說的內容。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"자, 잠깐!","JPN":"ま、待って！","ENG":"W-wait!","TWN":"等，等一下！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L32_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"응…… 말해.","JPN":"うん……どうぞ。","ENG":"Yes...?","TWN":"嗯……說吧。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"엇, 나도 모르게…… 이젠 할 말도 없는데……!","JPN":"はっ、つい声を出しちゃった……話すことなんてないのに……！","ENG":"Huh? Why did I do that...? I don't have anything else to say...!","TWN":"啊，我不自覺就……但我根本沒話要說……！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그러니까…… 오리엔테이션인데 너무 수업 얘기만 하는 거 아니야……?","JPN":"だから、その……オリエンテーションなのに、授業の話ばかりなんじゃない……？","ENG":"Um... this is supposed to be an orientation. But you only talked about class-related matters...","TWN":"那個……不是新學期說明會嗎，怎麼都在講上課的事……？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"그럼 무슨 얘길 해……?","JPN":"じゃあ、何を話せばいい……？","ENG":"What else am I supposed to talk about...?","TWN":"那你想說什麼……？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"어…… 첫사랑 이야기라던가?","JPN":"ええと……初恋の話とか？","ENG":"Uh... how about the story of your first love?","TWN":"呃……說說老師的初戀故事吧？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이게 선생님한테 못 하는 소리가 없어!","JPN":"先生に向かって何言ってるのよ！","ENG":"That's no way to talk to our teacher!","TWN":"你對老師真是沒大沒小的！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L46_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"내, 내가 뭘?!","JPN":"べ、別にいいじゃない！","ENG":"W-what did I do?!","TWN":"我，我做了什麼？！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"많은 가르침을 받고자 하는 마음은 이해한다만, 너무 지나친 것 같소.","JPN":"更なる学びを求める気持ちはわかりますが、度が過ぎたのではないでしょうか。","ENG":"I understand your desire to learn, but you went too far.","TWN":"在下理解你想要學習更多的心情，但這有點過了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"주변을 둘러보시오. 다른 학생들에게 폐가 되고 있잖소.","JPN":"周りをみてください。他の生徒たちが困惑しています。","ENG":"Look around. You are being a nuisance to the other students.","TWN":"看看周圍，你不是在給其他學生造成麻煩嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"헉! 설마 화난 건가……?","JPN":"はっ！　まさか怒ってる……？","ENG":"Yikes! Is she mad...?","TWN":"呃！生氣了嗎……？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아 저기, 그러니까……. 방금 말은 얼떨결에 나온 건데…….","JPN":"あ、あの、だから……今のはつい口が滑って……","ENG":"Uh... well, I didn't mean to say that…","TWN":"啊，那個……剛才的話是無意中說出來的……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"오리엔테이션인데도…… 열심히 잘 들어주는구나…….","JPN":"オリエンテーションなのに……一生懸命聞いてくれるんだね……","ENG":"It's only the orientation, but... you really paid attention in class...","TWN":"雖然只是說明會……但你聽得很認真呢……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"계속 말 걸어줘서 고마웠어……. 많이 떨렸거든……. 처음이라.","JPN":"たくさん発言してくれてありがとう……初めてだから……緊張したの。","ENG":"Thanks for engaging with me... It's my first time, so... I was very nervous.","TWN":"謝謝你一直和我說話……我真的很緊張……因為這是第一次。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"……엥?!","JPN":"……え！？","ENG":"...Huh?!","TWN":"……啊？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"하게 해줄게……. 내일 수업 때…… 실습.","JPN":"やらせてあげる……明日の授業で……実習。","ENG":"In tomorrow's class... I'll let you do... the simulation.","TWN":"我會同意的……明天上課時的……實習。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"열심히 했으니까…… 기대해 줘……?","JPN":"頑張ったから……楽しみにしてて……？","ENG":"I put a lot of work into it, so... hope you enjoy it...","TWN":"因為你很努力……期待一下……？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"역시 이사장님의 오랜 친우. 보통 내공이 아니구려.","JPN":"さすが理事長の古き親友。只者ではないですね。","ENG":"No wonder she is Ms. Chairwoman's old friend. She is no ordinary individual.","TWN":"果然是理事長的老朋友，真的很老練。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나이엘, 선생님이 너그럽게 넘어가 주신 것 같은데 나중에 꼭 사과드려.\xA0","JPN":"ナイエル、先生が大目にみてくれたんだから、後で必ず謝るんだよ。\xA0","ENG":"Naielle, Ms. Jin might have let it slide this time, but make sure you apologize to her later.\xA0","TWN":"奈爾，幸好老師不跟你計較，之後記得要道歉。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"사, 사과는 무슨?! 난 잘못한 거 없어!","JPN":"あ、謝るってなにを！？　私は悪くないわ！","ENG":"A-apologize?! I did nothing wrong!","TWN":"道，道歉什麼？！我沒做錯什麼！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥, 여유 부리는 것도 이번까지야. 난 아직 저 선생의 실력을 보지 못했다고.","JPN":"ふん、余裕を見せてられるのもここまでよ。私はまだあの先生の実力を見てないんだから。","ENG":"Hmph! This is it for her nonchalant attitude. I haven't even seen how strong she is yet.","TWN":"哼，這次就讓你得意一下吧。我還沒有見識過那位老師的實力呢。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L22_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"야, 아직 수업 안 끝났는데 어디가?","JPN":"ちょっと、まだ授業中なのにどこ行くのよ！","ENG":"Hey, class isn't over yet. Where are you going?","TWN":"喂，課還沒結束，你去哪？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"에휴……. 그놈의 자존심이란……","JPN":"まったく……プライドの塊なんだから……","ENG":"*Sigh* That pride of hers...","TWN":"唉…… 那傢伙的自尊心啊……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};